# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

from flask import Flask, redirect, request, session
from flask_oidc import OAuth2Flask, OpenIDConnect
import jwt

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your_secret_key'

oidc = OAuth2Flask(app)
oidc.register_client(
    client_id='your_client_id',
    client_secret='your_client_secret',
    provider_name='your_provider_name',
    token_endpoint_auth_method='client_secret_post',
    authorize_redirect_uri='your_authorize_redirect_uri',
    access_token_url='your_access_token_url',
    authorize_url='your_authorize_url',
    client_metadata_endpoint='your_client_metadata_endpoint',
)

@app.route('/')
def home():
    if 'user_claims' in session:
        return f"Welcome, {session['user_claims']['name']}!"
    else:
        return redirect(oidc.authorize_url)

@oidc.callback_handler
def callback():
    token_response = oidc.oauth2.exchange_code_for_tokens(request.args['code'])
    access_token = token_response['access_token']
    id_token = token_response['id_token']
    decoded_id_token = jwt.decode(id_token, options={'verify_signature': False})
    session['user_claims'] = decoded_id_token
    return redirect('/')

if __name__ == '__main__':
    app.run()